dashboard.definition:
{
    "dataSources": {
        "ds_asset_list": {
            "type": "ds.search",
            "options": {
                "query": "`maze_investigations` | spath path=\"related_scanner_findings{}.asset_name\" output=asset_name | mvexpand asset_name | dedup asset_name | sort asset_name | table asset_name",
                "queryParameters": {
                    "earliest": "-30d@d",
                    "latest": "now"
                }
            }
        },
        "ds_asset_kpis": {
            "type": "ds.search",
            "options": {
                "query": "`maze_investigations` | spath path=\"snapshot.status\" output=inv_status | search inv_status=\"$status_filter$\" | spath path=\"related_scanner_findings{}.asset_name\" output=asset_name | mvexpand asset_name | search asset_name=\"*$asset_filter$*\" | stats count as total, count(eval(exploitability=\"exploitable\")) as exploitable, count(eval(exploitability=\"not_exploitable\")) as not_exploitable",
                "queryParameters": {
                    "earliest": "$time_tok.earliest$",
                    "latest": "$time_tok.latest$"
                }
            }
        },
        "ds_asset_pie": {
            "type": "ds.search",
            "options": {
                "query": "`maze_investigations` | spath path=\"snapshot.status\" output=inv_status | search inv_status=\"$status_filter$\" | spath path=\"related_scanner_findings{}.asset_name\" output=asset_name | mvexpand asset_name | search asset_name=\"*$asset_filter$*\" | eval label=if(exploitability=\"exploitable\", \"Exploitable\", \"Not Exploitable\") | stats count by label",
                "queryParameters": {
                    "earliest": "$time_tok.earliest$",
                    "latest": "$time_tok.latest$"
                }
            }
        },
        "ds_asset_severity_bar": {
            "type": "ds.search",
            "options": {
                "query": "`maze_investigations` | spath path=\"snapshot.status\" output=inv_status | search inv_status=\"$status_filter$\" | spath path=\"related_scanner_findings{}.asset_name\" output=asset_name | mvexpand asset_name | search asset_name=\"*$asset_filter$*\" | eval severity_order=case(maze_severity=\"CRITICAL\", 1, maze_severity=\"HIGH\", 2, maze_severity=\"MEDIUM\", 3, maze_severity=\"LOW\", 4, maze_severity=\"NOT_EXPLOITABLE\", 5, 1=1, 6) | stats count by maze_severity severity_order | sort severity_order | fields - severity_order",
                "queryParameters": {
                    "earliest": "$time_tok.earliest$",
                    "latest": "$time_tok.latest$"
                }
            }
        },
        "ds_asset_cves": {
            "type": "ds.search",
            "options": {
                "query": "`maze_investigations` | spath path=\"snapshot.status\" output=inv_status | search inv_status=\"$status_filter$\" | spath path=\"related_scanner_findings{}.asset_name\" output=asset_name | mvexpand asset_name | search asset_name=\"*$asset_filter$*\" | spath path=\"snapshot.cvss.base_score\" output=cvss_score | eval severity_order=case(maze_severity=\"CRITICAL\", 1, maze_severity=\"HIGH\", 2, maze_severity=\"MEDIUM\", 3, maze_severity=\"LOW\", 4, maze_severity=\"NOT_EXPLOITABLE\", 5, 1=1, 6) | table cve_id maze_severity exploitability exploitability_reason cvss_score | sort severity_order",
                "queryParameters": {
                    "earliest": "$time_tok.earliest$",
                    "latest": "$time_tok.latest$"
                }
            }
        },
        "ds_root_cause": {
            "type": "ds.search",
            "options": {
                "query": "`maze_investigations` | spath path=\"snapshot.status\" output=inv_status | search inv_status=\"$status_filter$\" | spath path=\"related_scanner_findings{}.asset_name\" output=asset_name | mvexpand asset_name | search asset_name=\"*$asset_filter$*\" | spath path=\"vulnerability_root_cause_analysis{}\" output=rca_raw | mvexpand rca_raw | spath input=rca_raw path=\"title\" output=rca_title | spath input=rca_raw path=\"status\" output=rca_status | spath input=rca_raw path=\"reasoning\" output=rca_reasoning | search rca_title=* | table cve_id rca_title rca_status rca_reasoning | rename rca_title as \"Factor Title\", rca_status as \"Status\", rca_reasoning as \"Reasoning\"",
                "queryParameters": {
                    "earliest": "$time_tok.earliest$",
                    "latest": "$time_tok.latest$"
                }
            }
        }
    },
    "defaults": {},
    "inputs": {
        "input_time": {
            "type": "input.timerange",
            "title": "Time Range",
            "options": {
                "token": "time_tok",
                "defaultValue": "-30d@d,now"
            }
        },
        "input_asset": {
            "type": "input.dropdown",
            "title": "Asset Name",
            "options": {
                "token": "asset_filter",
                "defaultValue": "",
                "items": []
            },
            "dataSources": {
                "primary": "ds_asset_list"
            }
        },
        "input_status": {
            "type": "input.dropdown",
            "title": "Status",
            "options": {
                "token": "status_filter",
                "defaultValue": "open",
                "items": [
                    {"label": "Open", "value": "open"},
                    {"label": "Closed", "value": "closed"},
                    {"label": "All", "value": "*"}
                ]
            }
        }
    },
    "layout": {
        "type": "grid",
        "options": {
            "width": 1440,
            "height": 1400
        },
        "structure": [
            {
                "item": "viz_total",
                "type": "block",
                "position": { "x": 0, "y": 0, "w": 480, "h": 180 }
            },
            {
                "item": "viz_exploitable",
                "type": "block",
                "position": { "x": 480, "y": 0, "w": 480, "h": 180 }
            },
            {
                "item": "viz_not_exploitable",
                "type": "block",
                "position": { "x": 960, "y": 0, "w": 480, "h": 180 }
            },
            {
                "item": "viz_asset_pie",
                "type": "block",
                "position": { "x": 0, "y": 180, "w": 480, "h": 350 }
            },
            {
                "item": "viz_asset_severity_bar",
                "type": "block",
                "position": { "x": 480, "y": 180, "w": 960, "h": 350 }
            },
            {
                "item": "viz_asset_cves",
                "type": "block",
                "position": { "x": 0, "y": 530, "w": 1440, "h": 400 }
            },
            {
                "item": "viz_root_cause",
                "type": "block",
                "position": { "x": 0, "y": 930, "w": 1440, "h": 400 }
            }
        ],
        "globalInputs": ["input_time", "input_asset", "input_status"]
    },
    "visualizations": {
        "viz_total": {
            "type": "splunk.singlevalue",
            "title": "Total Investigations",
            "dataSources": { "primary": "ds_asset_kpis" },
            "options": {
                "majorValue": "> primary | seriesByName('total') | lastPoint()"
            }
        },
        "viz_exploitable": {
            "type": "splunk.singlevalue",
            "title": "Exploitable",
            "dataSources": { "primary": "ds_asset_kpis" },
            "options": {
                "majorValue": "> primary | seriesByName('exploitable') | lastPoint()",
                "majorColor": "#dc4e41"
            }
        },
        "viz_not_exploitable": {
            "type": "splunk.singlevalue",
            "title": "Not Exploitable",
            "dataSources": { "primary": "ds_asset_kpis" },
            "options": {
                "majorValue": "> primary | seriesByName('not_exploitable') | lastPoint()",
                "majorColor": "#53a051"
            }
        },
        "viz_asset_pie": {
            "type": "splunk.pie",
            "title": "Exploitability Breakdown",
            "dataSources": { "primary": "ds_asset_pie" },
            "options": {
                "seriesColors": ["#dc4e41", "#53a051"]
            }
        },
        "viz_asset_severity_bar": {
            "type": "splunk.bar",
            "title": "Severity Breakdown",
            "dataSources": { "primary": "ds_asset_severity_bar" },
            "options": {
                "xField": "maze_severity",
                "seriesColors": ["#af575a"]
            }
        },
        "viz_asset_cves": {
            "type": "splunk.table",
            "title": "CVEs for Asset",
            "dataSources": { "primary": "ds_asset_cves" },
            "options": {
                "count": 25
            }
        },
        "viz_root_cause": {
            "type": "splunk.table",
            "title": "Root Cause Factors",
            "dataSources": { "primary": "ds_root_cause" },
            "options": {
                "count": 25
            }
        }
    },
    "title": "Asset Drilldown"
}
